SourceCode.Declaration:
/// <summary>
/// Binds a channel handler implementation to a <c>ConDemoChannelType</c> value.
/// </summary>
public class ConDemoChannelAttribute extends SysAttribute implements SysExtensionIAttribute
{
    ConDemoChannelType channel;
}

Method.Source:
/// <summary>
/// Initializes a new instance of the <c>ConDemoChannelAttribute</c> class.
/// </summary>
/// <param name = "_channel">The channel the decorated class handles.</param>
public void new(ConDemoChannelType _channel)
{
    super();

    this.parmChannel(_channel);
}

/// <summary>
/// Gets or sets the channel the decorated class handles.
/// </summary>
/// <param name = "_channel">The channel the decorated class handles.</param>
/// <returns>The channel the decorated class handles.</returns>
public ConDemoChannelType parmChannel(ConDemoChannelType _channel = channel)
{
    channel = _channel;

    return channel;
}

/// <summary>
/// Returns the key used for storing cached data for this attribute.
/// </summary>
/// <returns>A string representing the cache key.</returns>
public str parmCacheKey()
{
    return classStr(ConDemoChannelAttribute) + ';' + int2str(enum2int(channel));
}

/// <summary>
/// Determines if the same instance should be returned by the extension framework.
/// </summary>
/// <returns>false, because a new instance is created for every invocation.</returns>
public boolean useSingleton()
{
    return false;
}
